        // But since this is the first allocation point, if ctx->temp_buffer is not NULL, 
        // it's likely caller-allocated. We will overwrite ctx->temp_buffer, potentially leaking the old one
        // if the caller doesn't save it. To be safe and simple:
        // We only manage the memory we malloc. If we malloc here, we set allocated_buffer = 1.

        unsigned char *new_buffer = (unsigned char *)malloc(expected_size);
        if (new_buffer == NULL) {
            goto cleanup;
        }

        ctx->temp_buffer = new_buffer;
        ctx->buffer_size = expected_size;
        allocated_buffer = 1; 
    }

    // 2. Data Decompression
    // Calculate payload length: Total - Header - Checksum
    payload_len = data_size - header_len - checksum_len;
    payload = &compressed_data[header_len];
    decompressed_data = ctx->temp_buffer; // Working pointer

    if (compression_type == 0) { // Raw
        if (payload_len != expected_size) {
            goto cleanup; // Size mismatch
        }
        memcpy(decompressed_data, payload, payload_len);
    } 
    else if (compression_type == 1) { // RLE
        size_t decompressed_pos = 0;
        size_t i = 0;

        while (i < payload_len) {
            if (i + 1 >= payload_len) {
                goto cleanup; // Malformed RLE stream (missing value byte)
            }

            unsigned char count = payload[i];
            unsigned char value = payload[i + 1];
            i += 2;

            // Check bounds
            if (decompressed_pos + count > expected_size) {
                goto cleanup; // Decompressed data exceeds buffer
            }

            memset(&decompressed_data[decompressed_pos], value, count);
            decompressed_pos += count;
        }

        if (decompressed_pos != expected_size) {
            goto cleanup; // Decompressed size mismatch
        }
    } 
    else {
        // Unsupported compression type
        goto cleanup;
    }

    // 3. Integrity Verification
    stored_checksum = compressed_data[data_size - 1];

    // Calculate simple checksum (sum of all bytes)
    calculated_checksum = 0;
    for (size_t i = 0; i < expected_size; i++) {
        calculated_checksum += decompressed_data[i];
    }

    if (calculated_checksum != stored_checksum) {
        goto cleanup;
    }

    // Success
    result = 0;

cleanup:
    // Resource Management and Error Handling
    // This block runs on every exit path (success or failure).
    // It ensures we only free memory that WE allocated.

    if (result != 0) {
        // An error occurred
        if (allocated_buffer && ctx->temp_buffer != NULL) {
            // We allocated the buffer, so we must free it to prevent leaks.
            free(ctx->temp_buffer);
            // CRITICAL: Set to NULL to prevent double-free by the caller or subsequent calls.
            ctx->temp_buffer = NULL;
            ctx->buffer_size = 0;
        }
        // If allocated_buffer is 0, ctx->temp_buffer belongs to the caller,
        // so we do NOT free it here.
    } else {
        // Success: The caller now owns the buffer (whether we allocated it or they provided a sufficient one).
        // We do not free it here.
        // If we allocated a new buffer, it is now in ctx->temp_buffer and allocated_buffer is 1.
        // The caller is responsible for freeing it later.
    }

    return result;
}
